import hashlib

def file_hash(filename):
    """Creates a hash of a file for integrity checking."""
    h = hashlib.sha256()
    b = bytearray(128*1024)
    mv = memoryview(b)
    with open(filename, "rb", buffering=False) as f:
        for n in iter(lambda: f.readinto(mv), 0):
            h.update(mv[:n])
    return h.hexdigest()